const HTML = "<!doctype html>\n<html lang=\"ru\">\n<head>\n<meta charset=\"utf-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n<title>Demo Eventobot — витрина с AI-линейкой (прототип)</title>\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n<link href=\"https://fonts.googleapis.com/css?family=Rubik:400,500,700,900&display=swap&subset=cyrillic,hebrew\" rel=\"stylesheet\">\n<script src=\"https://unpkg.com/react@18/umd/react.production.min.js\" crossorigin></script>\n<script src=\"https://unpkg.com/react-dom@18/umd/react-dom.production.min.js\" crossorigin></script>\n<script src=\"https://unpkg.com/@babel/standalone/babel.min.js\"></script>\n<script src=\"https://cdn.tailwindcss.com\"></script>\n<script>\n  tailwind.config = {\n    theme: {\n      extend: {\n        colors: {\n          evb: { DEFAULT:'#ED2025', 600:'#d81b20', 50:'#fdecec', 100:'#fbd7d8' },\n          ink: '#16161a',\n          deep:'#1f2c49',\n        },\n        fontFamily: { sans: ['Rubik','-apple-system','Segoe UI','sans-serif'] },\n        boxShadow: {\n          soft:'0 1px 2px rgba(16,22,30,.05), 0 10px 30px rgba(16,22,30,.07)',\n          lift:'0 16px 50px rgba(16,22,30,.16)',\n        }\n      }\n    }\n  }\n</script>\n<style>\n  html,body{background:#f3f4f6;font-family:'Rubik',sans-serif}\n  *{-webkit-font-smoothing:antialiased}\n  ::-webkit-scrollbar{height:8px;width:8px}\n  ::-webkit-scrollbar-thumb{background:#d6d8dd;border-radius:8px}\n  .no-sb::-webkit-scrollbar{display:none}\n  @keyframes fade{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:none}}\n  .fade{animation:fade .25s ease both}\n  @keyframes sheet{from{transform:translateY(100%)}to{transform:none}}\n  .sheet{animation:sheet .3s cubic-bezier(.2,.8,.2,1) both}\n  @keyframes pop{from{opacity:0;transform:scale(.96)}to{opacity:1;transform:none}}\n  .pop{animation:pop .2s ease both}\n  @keyframes pulse2{0%,100%{opacity:.35}50%{opacity:1}}\n  .typing span{display:inline-block;width:6px;height:6px;border-radius:99px;background:#9aa0ad;margin:0 1px;animation:pulse2 1.1s infinite}\n  .typing span:nth-child(2){animation-delay:.18s}.typing span:nth-child(3){animation-delay:.36s}\n  .clamp2{display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}\n</style>\n</head>\n<body class=\"text-ink\">\n<div id=\"root\"></div>\n\n<script>\n  // preset-react defaults to the automatic JSX runtime (emits `import \"react/jsx-runtime\"`),\n  // which breaks with UMD React globals. Register a classic-runtime variant.\n  Babel.registerPreset('react-classic', { presets: [[Babel.availablePresets['react'], { runtime:'classic' }]] });\n</script>\n<script type=\"text/babel\" data-presets=\"react-classic\">\nconst { useState, useMemo, useRef, useEffect } = React;\n\n/* ============================================================\n   ДАННЫЕ — реальные события демо-кассы demo.eventobot.net\n   ============================================================ */\nconst CATS = {\n  concert:   {label:'Concerts',   ru:'Концерты',  grad:'from-indigo-500 to-violet-700'},\n  children:  {label:'Children',   ru:'Детям',     grad:'from-sky-400 to-cyan-500'},\n  standup:   {label:'Stand-Up',   ru:'Стендап',   grad:'from-amber-500 to-orange-600'},\n  show:      {label:'Show',       ru:'Шоу',       grad:'from-fuchsia-500 to-pink-600'},\n  theater:   {label:'Theater',    ru:'Театр',     grad:'from-rose-500 to-red-600'},\n  exhibition:{label:'Exhibitions',ru:'Выставки',  grad:'from-emerald-500 to-teal-600'},\n  tour:      {label:'Tour',       ru:'Туры',      grad:'from-lime-500 to-green-600'},\n};\nconst NAV_CATS = ['concert','children','standup','show','theater','tour','exhibition'];\nconst CITIES = ['Все города','Haifa','Tel Aviv','Hamburg','Leipzig','Karlsruhe','Gütersloh','Poznań','Barcelona','Alicante','Riga'];\n\n// dd.mm.yy → today = 24.06.26 (ср). Ближайшая суббота = 27.06.26\nconst E = (o)=>o;\nconst EVENTS = [\n  E({id:'aerosmith', title:'Aerosmith', cat:'concert', city:'Haifa', venue:'Romema Arena', date:'04.07.26', time:'20:00', cur:'€', from:13, to:560, soldout:true, seated:true, kids:false, tag:'Super price',\n     desc:'Прощальный тур легендарной группы. Полный концерт с классической программой.'}),\n  E({id:'safronov', title:'Super magic of the Safronov brothers!', cat:'show', city:'Haifa', venue:'Haifa Auditorium', date:'27.06.26', time:'18:00', cur:'€', from:25, to:90, soldout:false, seated:true, kids:true, tag:'Our special offer',\n     desc:'Большое семейное иллюзионное шоу. Подходит детям от 5 лет, дневной сеанс.'}),\n  E({id:'fridman', title:'Vladimir Fridman — Anniversary Concerts', cat:'concert', city:'Tel Aviv', venue:'Charles Bronfman Auditorium', date:'27.06.26', time:'20:30', cur:'€', from:33, to:120, soldout:false, seated:true, kids:false, tag:null,\n     desc:'Юбилейный концерт с оркестром. Нумерованные места, партер и балкон.'}),\n  E({id:'usachev', title:'Concert meeting with Andrei Usachev', cat:'children', city:'Tel Aviv', venue:'Tzavta Hall', date:'28.06.26', time:'12:00', cur:'€', from:19, to:45, soldout:false, seated:false, kids:true, tag:'Discount',\n     desc:'Тёплая встреча с детским писателем. Стихи, песни и автограф-сессия.'}),\n  E({id:'fixie', title:'Fixie-show «How Dim Dimych became Fixik»', cat:'children', city:'Leipzig', venue:'Haus Auensee', date:'27.06.26', time:'11:00', cur:'€', from:15, to:35, soldout:false, seated:false, kids:true, tag:'Discount',\n     desc:'Интерактивное детское шоу по мотивам Фиксиков. Утренний сеанс.'}),\n  E({id:'rondo', title:'35 years to the group «RONDO»', cat:'concert', city:'Hamburg', venue:'Barclays Arena', date:'11.07.26', time:'19:00', cur:'€', from:39, to:139, soldout:false, seated:true, kids:false, tag:null,\n     desc:'Юбилейный концерт. Все хиты вживую, большой состав.'}),\n  E({id:'v2', title:'V2 share event', cat:'show', city:'Poznań', venue:'MTP Hall', date:'27.08.26', dateTo:'30.09.26', time:'19:00', cur:'€', from:89, to:289, soldout:false, seated:true, kids:false, tag:'Super price',\n     desc:'Гастрольное шоу, серия показов в течение месяца.'}),\n  E({id:'scratch', title:'From scratch', cat:'theater', city:'Gütersloh', venue:'Stadthalle', date:'03.07.26', time:'20:00', cur:'€', from:175, to:400, soldout:false, seated:true, kids:false, tag:null,\n     desc:'Премьерный спектакль приглашённой труппы.'}),\n  E({id:'kim', title:'Julius Kim «Bouquet of herbs»', cat:'concert', city:'Karlsruhe', venue:'Konzerthaus', date:'05.07.26', time:'19:30', cur:'€', from:29, to:59, soldout:false, seated:true, kids:false, tag:null,\n     desc:'Авторский вечер песен под гитару.'}),\n  E({id:'there', title:'There, then', cat:'theater', city:'Alicante', venue:'Teatro Principal', date:'28.06.26', time:'20:00', cur:'€', from:20, to:75, soldout:false, seated:true, kids:false, tag:null,\n     desc:'Камерная драма, ограниченное число показов.'}),\n  E({id:'standup', title:'Stand-Up Night Riga', cat:'standup', city:'Riga', venue:'Splendid Palace', date:'27.06.26', time:'21:00', cur:'€', from:19, to:39, soldout:false, seated:false, kids:false, tag:null,\n     desc:'Вечер стендапа, 16+.'}),\n  E({id:'test2', title:'Test event 2', cat:'exhibition', city:'Alicante', venue:'MACA', date:'20.06.26', dateTo:'31.08.26', time:'10:00', cur:'£', from:15, to:200, soldout:false, seated:false, kids:true, tag:null,\n     desc:'Выставка по сеансам, мультивалютная продажа (£).'}),\n];\nconst byId = (id)=>EVENTS.find(e=>e.id===id);\nconst dateLabel = (e)=> e.dateTo ? `${e.date} – ${e.dateTo}` : e.date;\n// «27.06.26» → день недели\nconst dow = (d)=>{ if(!d) return null; const [dd,mm,yy]=d.split('.').map(Number); const dt=new Date(2000+yy,mm-1,dd); return dt.getDay(); };\nconst isWeekend = (e)=>{ const g=dow(e.date); return g===6||g===0; };\n\n/* ============================================================\n   ОБЩИЕ ЭЛЕМЕНТЫ ВИТРИНЫ\n   ============================================================ */\nfunction Poster({e, h='h-44', rounded='rounded-t-xl'}){\n  const c=CATS[e.cat];\n  return (\n    <div className={`relative ${h} ${rounded} overflow-hidden bg-gradient-to-br ${c.grad}`}>\n      <div className=\"absolute inset-0 opacity-25\"\n        style={{backgroundImage:'radial-gradient(circle at 22% 18%, #fff 0, transparent 42%), radial-gradient(circle at 82% 70%, #fff 0, transparent 38%)'}}/>\n      <span className=\"absolute top-2 left-2 text-[11px] font-medium text-white/95 bg-black/25 backdrop-blur px-2 py-0.5 rounded-full\">{c.label}</span>\n      {e.soldout && <span className=\"absolute top-2 right-2 text-[11px] font-bold text-white bg-black/70 px-2 py-0.5 rounded-full\">SOLD OUT</span>}\n      <div className=\"absolute bottom-2 left-2 right-2 text-white font-bold drop-shadow text-[14px] leading-tight clamp2\">{e.title}</div>\n    </div>\n  );\n}\n\nfunction AIBadge({label='AI', className=''}){\n  return <span className={`inline-flex items-center gap-1 text-[10px] font-bold tracking-wide text-evb bg-evb-50 border border-evb-100 px-1.5 py-0.5 rounded ${className}`}>\n    <span className=\"w-1.5 h-1.5 rounded-full bg-evb\"></span>{label}</span>;\n}\n\nfunction PinIcon({className='w-3.5 h-3.5'}){return(\n  <svg className={className} viewBox=\"0 0 15 20\" fill=\"currentColor\"><path fillRule=\"evenodd\" clipRule=\"evenodd\" d=\"M7.5 0C11.642 0 15 3.276 15 7.316 15 11.356 7.5 20 7.5 20S0 11.356 0 7.316C0 3.276 3.358 0 7.5 0zm0 4.6a2.7 2.7 0 100 5.4 2.7 2.7 0 000-5.4z\"/></svg>);}\nfunction CalIcon({className='w-3.5 h-3.5'}){return(\n  <svg className={className} viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" strokeWidth=\"2\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\"/><path d=\"M16 2v4M8 2v4M3 10h18\"/></svg>);}\n\n/* Карточка события в стиле demo.eventobot — красная кнопка Buy ticket */\nfunction EventCard({e, onOpen, why}){\n  return (\n    <div className=\"bg-white rounded-xl border border-slate-200 shadow-soft overflow-hidden flex flex-col hover:shadow-lift transition-shadow\">\n      <button onClick={()=>onOpen(e)} className=\"text-left\"><Poster e={e}/></button>\n      <div className=\"p-3 flex flex-col flex-1\">\n        {e.tag && <span className=\"self-start mb-1.5 text-[10px] font-bold uppercase tracking-wide text-evb bg-evb-50 px-2 py-0.5 rounded\">{e.tag}</span>}\n        <button onClick={()=>onOpen(e)} className=\"text-left text-[14px] font-bold leading-snug clamp2 hover:text-evb transition-colors\">{e.title}</button>\n        <div className=\"mt-1.5 space-y-1 text-[12px] text-slate-500\">\n          <div className=\"flex items-center gap-1.5\"><CalIcon/> {dateLabel(e)} · {e.time}</div>\n          <div className=\"flex items-center gap-1.5\"><PinIcon/> {e.city} · {e.venue}</div>\n        </div>\n        {why && <div className=\"mt-2 text-[12px] text-deep bg-slate-50 border-l-2 border-evb rounded-r px-2 py-1.5 leading-snug\">{why}</div>}\n        <div className=\"mt-auto pt-3 flex items-center justify-between\">\n          <div className=\"text-[13px]\"><span className=\"text-slate-400 text-[11px]\">от </span><span className=\"font-bold\">{e.cur}{e.from}</span></div>\n          {e.soldout\n            ? <button onClick={()=>onOpen(e)} className=\"text-[12px] font-bold text-slate-500 bg-slate-100 px-3 py-1.5 rounded\">No tickets</button>\n            : <button onClick={()=>onOpen(e)} className=\"text-[12px] font-bold text-white bg-evb hover:bg-evb-600 px-4 py-1.5 rounded transition-colors\">Buy ticket</button>}\n        </div>\n      </div>\n    </div>\n  );\n}\n\n/* ====== ШАПКА витрины ====== */\nfunction StoreHeader({mobile, onHome}){\n  return (\n    <header className=\"bg-white border-b border-slate-200\">\n      <div className=\"max-w-[1200px] mx-auto px-4 h-16 flex items-center gap-4\">\n        <button onClick={onHome} className=\"flex items-center gap-2 shrink-0\">\n          <span className=\"w-9 h-9 rounded-lg bg-evb text-white grid place-items-center font-black text-[16px]\">e</span>\n          <span className=\"font-black text-[17px] tracking-tight leading-none\">Demo&nbsp;<span className=\"text-evb\">Eventobot</span></span>\n        </button>\n        {!mobile && (\n          <nav className=\"flex items-center gap-4 ml-3 text-[13px] text-slate-600\">\n            {NAV_CATS.slice(0,6).map(c=><a key={c} className=\"hover:text-evb cursor-pointer\">{CATS[c].label}</a>)}\n          </nav>\n        )}\n        <div className=\"ml-auto flex items-center gap-3 text-[12px] text-slate-500\">\n          {!mobile && <span className=\"hidden lg:flex items-center gap-1 font-medium text-slate-700\"><svg className=\"w-3.5 h-3.5 text-evb\" viewBox=\"0 0 24 24\" fill=\"currentColor\"><path d=\"M6.6 10.8a15 15 0 006.6 6.6l2.2-2.2a1 1 0 011-.24 11.4 11.4 0 003.6.57 1 1 0 011 1V20a1 1 0 01-1 1A17 17 0 013 4a1 1 0 011-1h3.5a1 1 0 011 1 11.4 11.4 0 00.57 3.6 1 1 0 01-.24 1z\"/></svg>+972 50-815-4463</span>}\n          <span className=\"flex items-center gap-1 px-2 py-1 rounded border border-slate-200\">RU<svg className=\"w-3 h-3\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" strokeWidth=\"2\"><path d=\"m6 9 6 6 6-6\"/></svg></span>\n          {!mobile && <button className=\"font-semibold text-evb border border-evb-100 bg-evb-50 px-3 py-1.5 rounded\">Partner login</button>}\n        </div>\n      </div>\n    </header>\n  );\n}\n\n/* ====== ГЕРОЙ + AI-SMART SEARCH (форма: enriched поиск) ====== */\nconst SLIDES = [\n  'https://demo.eventobot.net/sbadmin/storage/slider/06/23/02/03/1920_539_693932800a40b.jpg',\n  'https://demo.eventobot.net/sbadmin/storage/slider/00/28/21/18/1920_539_69e0a4b83eaef.jpg',\n  'https://demo.eventobot.net/sbadmin/storage/slider/15/11/09/06/1920_539_69b1553a777f3.jpg',\n];\nfunction Hero({onSearch, focus}){\n  const [i,setI]=useState(0);\n  useEffect(()=>{const t=setInterval(()=>setI(x=>(x+1)%SLIDES.length),4500);return()=>clearInterval(t);},[]);\n  return (\n    <div className=\"relative\">\n      <div className=\"relative h-[230px] md:h-[300px] bg-deep overflow-hidden\">\n        {SLIDES.map((s,k)=>(\n          <img key={k} src={s} alt=\"\" className={`absolute inset-0 w-full h-full object-cover transition-opacity duration-700 ${k===i?'opacity-100':'opacity-0'}`}/>\n        ))}\n        <div className=\"absolute inset-0 bg-gradient-to-t from-black/55 via-black/10 to-transparent\"/>\n        <div className=\"absolute left-1/2 bottom-3 -translate-x-1/2 flex gap-1.5\">\n          {SLIDES.map((_,k)=><span key={k} className={`w-1.5 h-1.5 rounded-full ${k===i?'bg-white':'bg-white/40'}`}/>)}\n        </div>\n      </div>\n      {/* AI Smart Search вынесен поверх героя — нативная часть витрины */}\n      <div className=\"max-w-[1200px] mx-auto px-4\">\n        <div className=\"-mt-7 relative z-10\">\n          <SmartSearch onSearch={onSearch} autofocus={focus}/>\n        </div>\n      </div>\n    </div>\n  );\n}\n\nfunction SmartSearch({onSearch, autofocus}){\n  const [q,setQ]=useState('');\n  const ref=useRef();\n  useEffect(()=>{ if(autofocus&&ref.current){ref.current.focus(); ref.current.scrollIntoView({block:'center'});} },[autofocus]);\n  const samples=['с ребёнком в Хайфе в субботу до 40 €','Aerosmith','семейное шоу на выходных'];\n  return (\n    <div className=\"bg-white rounded-2xl shadow-lift border border-slate-200 p-2 md:p-2.5\">\n      <div className=\"flex items-center gap-2\">\n        <div className=\"pl-2 text-slate-400\"><svg className=\"w-5 h-5\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" strokeWidth=\"2\"><circle cx=\"11\" cy=\"11\" r=\"7\"/><path d=\"m21 21-4.3-4.3\"/></svg></div>\n        <input ref={ref} value={q} onChange={e=>setQ(e.target.value)} onKeyDown={e=>{if(e.key==='Enter'&&q.trim())onSearch(q.trim())}}\n          placeholder=\"Поиск событий — обычный или живым языком…\"\n          className=\"flex-1 text-[14px] outline-none py-2\"/>\n        <AIBadge label=\"AI поиск\" className=\"mr-1 hidden sm:inline-flex\"/>\n        <button onClick={()=>q.trim()&&onSearch(q.trim())} className=\"text-[13px] font-bold text-white bg-evb hover:bg-evb-600 rounded-xl px-5 py-2.5\">Найти</button>\n      </div>\n      <div className=\"flex gap-2 mt-1.5 px-1 pb-0.5 flex-wrap\">\n        <span className=\"text-[11px] text-slate-400 py-1\">Примеры:</span>\n        {samples.map(s=><button key={s} onClick={()=>{setQ(s);onSearch(s);}} className=\"text-[12px] text-slate-600 border border-slate-200 rounded-full px-2.5 py-1 hover:border-evb hover:text-evb\">{s}</button>)}\n      </div>\n    </div>\n  );\n}\n\n/* Разбор живого запроса → подтверждение фильтров + результаты */\nfunction parseQuery(text){\n  const t=text.toLowerCase();\n  const natural=/ребен|ребён|дет|семей|субб|воскрес|выход|до \\d|деше|вечер|сегодня/i.test(t);\n  if(!natural){\n    const list=EVENTS.filter(e=>e.title.toLowerCase().includes(t)||CATS[e.cat].label.toLowerCase().includes(t)||e.city.toLowerCase().includes(t));\n    return {natural:false, list, q:text};\n  }\n  const f={};\n  if(/ребен|ребён|дет|семей/.test(t)) f.kids=true;\n  const cityHit=CITIES.find(c=>c!=='Все города'&&(t.includes(c.toLowerCase())||(c==='Haifa'&&t.includes('хайф'))||(c==='Tel Aviv'&&t.includes('тель'))));\n  if(cityHit) f.city=cityHit;\n  if(/субб|воскрес|выход/.test(t)) f.weekend=true;\n  const m=t.match(/до\\s*(\\d+)/); if(m) f.max=Number(m[1]);\n  let list=EVENTS.filter(e=>(!f.kids||e.kids)&&(!f.city||e.city===f.city)&&(!f.weekend||isWeekend(e))&&(f.max==null||e.from<=f.max));\n  return {natural:true, list, f, q:text};\n}\n\n/* ====== СЕКЦИИ событий ====== */\nfunction Section({title, children, sub}){\n  return (\n    <section className=\"max-w-[1200px] mx-auto px-4 mt-9\">\n      <div className=\"flex items-end justify-between mb-4\">\n        <div>\n          <h2 className=\"text-[20px] font-black tracking-tight\">{title}</h2>\n          {sub && <div className=\"text-[12px] text-slate-400\">{sub}</div>}\n        </div>\n        <a className=\"text-[12px] font-semibold text-evb cursor-pointer\">Все →</a>\n      </div>\n      {children}\n    </section>\n  );\n}\n\n/* ============================================================\n   ВИДЖЕТ CONCIERGE — плавающий чат (форма: corner widget)\n   ============================================================ */\nfunction ConciergeWidget({mobile, open, setOpen, onOpenEvent}){\n  const [msgs,setMsgs]=useState([{role:'ai',text:'Здравствуйте! Помогу выбрать событие или подскажу по возврату и оплате. Что ищете?'}]);\n  const [stage,setStage]=useState('idle');\n  const [typing,setTyping]=useState(false);\n  const bodyRef=useRef();\n  useEffect(()=>{if(bodyRef.current)bodyRef.current.scrollTop=bodyRef.current.scrollHeight;},[msgs,typing]);\n  const push=m=>setMsgs(x=>[...x,m]);\n  const ai=fn=>{setTyping(true);setTimeout(()=>{setTyping(false);fn();},650);};\n\n  const send=(text)=>{\n    push({role:'user',text});\n    if(/верн|возврат|сдать|обмен/i.test(text)){\n      ai(()=>push({role:'ai',text:'Возврат — не позднее чем за 48 часов до события, через личный кабинет → «Мои билеты». Сервисный сбор не возвращается, деньги приходят за 5–7 дней.',src:'из правил кассы Demo Eventobot'}));return;\n    }\n    if(/оплат|карт|рассроч|pay/i.test(text)){\n      ai(()=>push({role:'ai',text:'Принимаем Visa/Mastercard и Apple Pay. Оплата в валюте события (€ или £). Билет приходит на e-mail сразу после оплаты.',src:'из правил кассы'}));return;\n    }\n    if(stage==='idle' && /ребен|ребён|дет|семей/i.test(text)){\n      setStage('ask');\n      ai(()=>push({role:'ai',text:'Уточню одно: возраст ребёнка — до 6 или постарше? Это поможет отобрать подходящее.',chips:['До 6 лет','6–12 лет']}));return;\n    }\n    if(stage==='ask'){\n      setStage('done');\n      const list=EVENTS.filter(e=>e.kids&&(e.city==='Haifa'||e.city==='Tel Aviv')).slice(0,3);\n      ai(()=>push({role:'ai',text:'Вот что подойдёт для ребёнка на ближайшие выходные:',cards:list,\n        whys:{safronov:'Дневной сеанс, иллюзия — детям от 5',usachev:'Спокойный формат, автограф-сессия',test2:'Выставка по сеансам, можно с коляской'}}));return;\n    }\n    ai(()=>push({role:'ai',text:'Не уверен, что понял точно — могу соединить с кассой, ответят за пару минут.',action:'contact'}));\n  };\n\n  const Body=(\n    <>\n      <div ref={bodyRef} className=\"flex-1 overflow-y-auto px-3.5 py-3 space-y-3 no-sb\">\n        {msgs.map((m,i)=>(\n          <div key={i} className={`fade ${m.role==='user'?'flex justify-end':''}`}>\n            {m.role==='user'\n              ? <div className=\"max-w-[80%] bg-evb text-white text-[13px] rounded-2xl rounded-br-md px-3 py-2\">{m.text}</div>\n              : <div className=\"max-w-[90%]\">\n                  <div className=\"bg-white border border-slate-200 text-[13px] rounded-2xl rounded-bl-md px-3 py-2 text-slate-700\">{m.text}\n                    {m.src && <div className=\"mt-1 text-[11px] text-slate-400\">Источник: {m.src}</div>}</div>\n                  {m.chips && <div className=\"flex gap-2 mt-2 flex-wrap\">{m.chips.map(c=><button key={c} onClick={()=>send(c)} className=\"text-[12px] border border-slate-300 rounded-full px-3 py-1 hover:bg-slate-50\">{c}</button>)}</div>}\n                  {m.cards && <div className=\"grid gap-2 mt-2\">{m.cards.map(e=><MiniCard key={e.id} e={e} why={m.whys?.[e.id]} onOpen={onOpenEvent}/>)}</div>}\n                  {m.action==='contact' && <button className=\"mt-2 text-[12px] font-bold text-evb border border-evb-100 bg-evb-50 rounded-lg px-3 py-1.5\">Написать в кассу</button>}\n                </div>}\n          </div>\n        ))}\n        {typing && <div className=\"typing bg-white border border-slate-200 inline-flex rounded-2xl rounded-bl-md px-3 py-2.5\"><span></span><span></span><span></span></div>}\n      </div>\n      <div className=\"p-3 border-t border-slate-100 bg-white\">\n        {msgs.length<=1 && <div className=\"flex gap-2 mb-2 flex-wrap\">{['Хочу с ребёнком в Хайфе в выходные','Как вернуть билет?'].map(s=>\n          <button key={s} onClick={()=>send(s)} className=\"text-[12px] text-slate-600 border border-slate-200 rounded-full px-3 py-1 hover:bg-slate-50\">{s}</button>)}</div>}\n        <ChatInput onSend={send}/>\n      </div>\n    </>\n  );\n\n  return (\n    <>\n      {!open &&\n        <button onClick={()=>setOpen(true)}\n          className=\"fixed z-40 bottom-5 right-5 flex items-center gap-2 bg-ink text-white text-[13px] font-semibold pl-3 pr-4 py-3 rounded-full shadow-lift hover:bg-black transition\">\n          <span className=\"w-2 h-2 rounded-full bg-emerald-400\"></span>Помощь с выбором\n        </button>}\n      {open && (mobile\n        ? <div className=\"fixed inset-0 z-50 flex items-end\">\n            <div className=\"absolute inset-0 bg-black/30\" onClick={()=>setOpen(false)}/>\n            <div className=\"sheet relative w-full h-[80%] bg-slate-50 rounded-t-2xl flex flex-col shadow-lift\">\n              <WidgetHead mobile onClose={()=>setOpen(false)}/>{Body}\n            </div>\n          </div>\n        : <div className=\"fixed z-50 bottom-5 right-5 w-[370px] h-[540px] bg-slate-50 rounded-2xl shadow-lift border border-slate-200 flex flex-col pop\">\n            <WidgetHead onClose={()=>setOpen(false)}/>{Body}\n          </div>)}\n    </>\n  );\n}\nfunction WidgetHead({onClose,mobile}){\n  return (\n    <div className={`h-12 flex items-center px-4 border-b border-slate-100 bg-white ${mobile?'rounded-t-2xl':'rounded-t-2xl'}`}>\n      {mobile && <div className=\"w-9 h-1 bg-slate-200 rounded-full absolute left-1/2 -translate-x-1/2 top-2\"/>}\n      <span className=\"font-bold text-[14px]\">Помощник кассы</span>\n      <AIBadge className=\"ml-2\"/>\n      <button onClick={onClose} className=\"ml-auto text-slate-400 text-[20px] leading-none hover:text-slate-600\">×</button>\n    </div>\n  );\n}\nfunction MiniCard({e,why,onOpen}){\n  return (\n    <div className=\"bg-white border border-slate-200 rounded-xl overflow-hidden\">\n      <button onClick={()=>onOpen(e)} className=\"block w-full text-left\"><Poster e={e} h=\"h-20\" rounded=\"rounded-none\"/></button>\n      <div className=\"p-2.5\">\n        <div className=\"text-[13px] font-bold leading-snug clamp2\">{e.title}</div>\n        <div className=\"text-[11px] text-slate-500 mt-0.5\">{e.city} · {dateLabel(e)}</div>\n        {why && <div className=\"mt-1.5 text-[11px] text-deep bg-slate-50 border-l-2 border-evb rounded-r px-2 py-1\">{why}</div>}\n        <div className=\"mt-2 flex items-center justify-between\">\n          <span className=\"text-[12px] font-bold\">от {e.cur}{e.from}</span>\n          <button onClick={()=>onOpen(e)} className=\"text-[11px] font-bold text-white bg-evb rounded px-3 py-1\">Buy</button>\n        </div>\n      </div>\n    </div>\n  );\n}\nfunction ChatInput({onSend}){\n  const [v,setV]=useState('');\n  return (\n    <form onSubmit={e=>{e.preventDefault();if(v.trim()){onSend(v.trim());setV('');}}} className=\"flex gap-2\">\n      <input value={v} onChange={e=>setV(e.target.value)} placeholder=\"Сообщение…\" className=\"flex-1 text-[13px] border border-slate-200 rounded-xl px-3 py-2 outline-none focus:border-evb\"/>\n      <button className=\"text-[13px] font-bold text-white bg-evb rounded-xl px-3\">→</button>\n    </form>\n  );\n}\n\n/* ============================================================\n   EVENT Q&A — инлайн AI-панель на странице события\n   ============================================================ */\nfunction EventQA({e}){\n  const QA={\n    'Во сколько двери?':{a:`Двери открываются за 45 минут до начала. Старт в ${e.time}. Рекомендуем прийти заранее — вход по сканированию билета.`,src:'из расписания события'},\n    'Можно ли с детьми?': e.kids\n      ? {a:'Да, событие подходит для детей. Дети до 3 лет — без отдельного места на руках у родителя.',src:'из правил площадки'}\n      : {a:'Событие рассчитано на взрослую аудиторию (16+). С маленькими детьми вход не предусмотрен.',src:'из правил площадки'},\n    'Есть парковка?':{a:`Рядом с «${e.venue}» есть платная городская парковка (~3 ${e.cur}/час). Ближайшая остановка транспорта — в 5 минутах пешком.`,src:'из правил площадки'},\n    'Возврат билета':{a:'Возврат возможен не позднее 48 часов до события через личный кабинет. Сервисный сбор не возвращается.',src:'из правил кассы'},\n  };\n  const [asked,setAsked]=useState([]);\n  const [typing,setTyping]=useState(false);\n  const ask=qq=>{ if(asked.find(x=>x.q===qq))return; setTyping(true); setTimeout(()=>{setTyping(false);setAsked(a=>[...a,{q:qq,...QA[qq]}]);},550); };\n  return (\n    <div className=\"mt-4 border border-slate-200 rounded-2xl bg-white p-4\">\n      <div className=\"flex items-center gap-2\">\n        <div className=\"text-[14px] font-bold\">Вопрос о событии?</div>\n        <AIBadge/>\n      </div>\n      <div className=\"text-[12px] text-slate-400 mt-0.5 mb-3\">Быстрый ответ из правил площадки и кассы — встроено прямо в страницу</div>\n      <div className=\"flex gap-2 flex-wrap\">\n        {Object.keys(QA).map(qq=><button key={qq} onClick={()=>ask(qq)} className=\"text-[12px] border border-slate-200 rounded-full px-3 py-1.5 hover:border-evb hover:bg-evb-50/50\">{qq}</button>)}\n      </div>\n      <div className=\"mt-3 space-y-2\">\n        {asked.map((x,i)=>(\n          <div key={i} className=\"fade bg-slate-50 rounded-xl p-3\">\n            <div className=\"text-[13px] font-semibold text-slate-700\">{x.q}</div>\n            <div className=\"text-[13px] text-slate-600 mt-0.5\">{x.a}</div>\n            <div className=\"text-[11px] text-slate-400 mt-1\">Источник: {x.src}</div>\n          </div>\n        ))}\n        {typing && <div className=\"typing bg-slate-50 inline-flex rounded-xl px-3 py-2.5\"><span></span><span></span><span></span></div>}\n      </div>\n      <div className=\"mt-3 pt-3 border-t border-slate-100\">\n        <ChatInput onSend={t=>setAsked(a=>[...a,{q:t,a:'Передал вопрос кассе — ответ придёт сюда и на e-mail в течение нескольких минут.',src:'касса Demo Eventobot'}])}/>\n      </div>\n    </div>\n  );\n}\n\n/* ============================================================\n   SEAT ADVISOR — интегрированное ИИ-окно (модалка) на странице\n   ============================================================ */\nfunction SeatAdvisorModal({e, mobile, onClose}){\n  const rows='ABCDEFGH'.split('');\n  const cols=12;\n  const rowPrice=r=>({A:e.to,B:e.to,C:Math.round(e.to*0.7),D:Math.round(e.to*0.7),E:Math.round((e.from+e.to)/2),F:Math.round((e.from+e.to)/2),G:e.from,H:e.from}[r]);\n  const taken=useMemo(()=>new Set(['A3','A4','B7','B8','C1','C2','C5','C6','D9','D10','E6','F11','G4','H8','H9']),[]);\n  const [n,setN]=useState(4);\n  const [maxP,setMaxP]=useState(rowPrice('C'));\n  const [picked,setPicked]=useState(null);\n  const find=()=>{\n    for(const r of rows){ if(rowPrice(r)>maxP)continue;\n      for(let c=1;c<=cols-n+1;c++){ const seats=Array.from({length:n},(_,i)=>`${r}${c+i}`);\n        if(seats.every(s=>!taken.has(s))){setPicked({seats:new Set(seats),row:r,price:rowPrice(r)});return;} } }\n    setPicked({seats:new Set(),row:null});\n  };\n  const prices=[...new Set(rows.map(rowPrice))].sort((a,b)=>a-b);\n  return (\n    <div className=\"fixed inset-0 z-50 flex items-end md:items-center justify-center p-0 md:p-6\">\n      <div className=\"absolute inset-0 bg-black/40\" onClick={onClose}/>\n      <div className={`relative bg-white w-full md:max-w-2xl ${mobile?'sheet rounded-t-2xl max-h-[88%]':'pop rounded-2xl'} overflow-y-auto shadow-lift`}>\n        <div className=\"sticky top-0 bg-white border-b border-slate-100 px-4 py-3 flex items-center gap-2 z-10\">\n          <span className=\"font-bold text-[15px]\">Подбор мест</span><AIBadge/>\n          <span className=\"text-[12px] text-slate-400 hidden sm:inline\">· {e.title}</span>\n          <button onClick={onClose} className=\"ml-auto text-slate-400 text-[22px] leading-none\">×</button>\n        </div>\n        <div className=\"p-4\">\n          <div className=\"bg-slate-50 border border-slate-200 rounded-xl p-3 mb-3 flex flex-wrap items-center gap-2\">\n            <span className=\"text-[13px] text-slate-500\">Найти</span>\n            <select value={n} onChange={ev=>setN(+ev.target.value)} className=\"text-[13px] border border-slate-200 rounded-lg px-2 py-1.5 bg-white\">{[2,3,4,5,6].map(x=><option key={x} value={x}>{x} места рядом</option>)}</select>\n            <span className=\"text-[13px] text-slate-500\">до</span>\n            <select value={maxP} onChange={ev=>setMaxP(+ev.target.value)} className=\"text-[13px] border border-slate-200 rounded-lg px-2 py-1.5 bg-white\">{prices.map(x=><option key={x} value={x}>{e.cur}{x} / место</option>)}</select>\n            <button onClick={find} className=\"text-[13px] font-bold text-white bg-evb hover:bg-evb-600 rounded-lg px-4 py-1.5\">Подобрать</button>\n          </div>\n          <div className=\"bg-gradient-to-b from-slate-100 to-white rounded-xl border border-slate-200 p-4 overflow-x-auto\">\n            <div className=\"mx-auto w-fit\">\n              <div className=\"text-center text-[11px] tracking-[.3em] text-slate-400 bg-slate-200/70 rounded py-1 mb-4\">СЦЕНА</div>\n              <div className=\"space-y-1.5\">\n                {rows.map(r=>(\n                  <div key={r} className=\"flex items-center gap-1.5 justify-center\">\n                    <span className=\"w-4 text-[11px] text-slate-400\">{r}</span>\n                    {Array.from({length:cols},(_,i)=>{const id=`${r}${i+1}`,tk=taken.has(id),pk=picked?.seats.has(id);\n                      let cls=tk?'bg-slate-300/60':'bg-emerald-200'; if(pk)cls='bg-evb ring-2 ring-evb-100';\n                      return <div key={id} title={`${id} · ${e.cur}${rowPrice(r)}`} className={`w-5 h-5 rounded-[5px] ${cls} ${pk?'scale-110':''} transition-all`}/>;})}\n                    <span className=\"w-9 text-[10px] text-slate-400 text-right\">{e.cur}{rowPrice(r)}</span>\n                  </div>\n                ))}\n              </div>\n              <div className=\"flex items-center gap-4 justify-center mt-4 text-[11px] text-slate-500\">\n                <span className=\"flex items-center gap-1\"><i className=\"w-3 h-3 rounded bg-emerald-200 inline-block\"/>свободно</span>\n                <span className=\"flex items-center gap-1\"><i className=\"w-3 h-3 rounded bg-slate-300/60 inline-block\"/>занято</span>\n                <span className=\"flex items-center gap-1\"><i className=\"w-3 h-3 rounded bg-evb inline-block\"/>подобрано AI</span>\n              </div>\n            </div>\n          </div>\n          {picked && picked.row && (\n            <div className=\"fade mt-3 bg-evb-50 border border-evb-100 rounded-xl p-3 flex flex-wrap items-center gap-3\">\n              <div>\n                <div className=\"text-[13px] font-bold\">Ряд {picked.row}, места {[...picked.seats].map(s=>s.slice(1)).join(', ')}</div>\n                <div className=\"text-[12px] text-slate-500\">{n} мест рядом · {e.cur}{picked.price}/место · итого {e.cur}{picked.price*n}</div>\n              </div>\n              <button className=\"ml-auto text-[13px] font-bold text-white bg-evb hover:bg-evb-600 rounded-lg px-5 py-2\">Забронировать эти</button>\n            </div>\n          )}\n          {picked && !picked.row && <div className=\"fade mt-3 bg-amber-50 border border-amber-200 text-amber-800 text-[13px] rounded-xl px-4 py-3\">Не нашлось {n} мест рядом до {e.cur}{maxP}. Увеличьте бюджет или уменьшите число мест.</div>}\n        </div>\n      </div>\n    </div>\n  );\n}\n\n/* ============================================================\n   DEMAND CATCHER — инлайн-блок на sold-out событии\n   ============================================================ */\nfunction DemandCatcher({e, onOpenEvent}){\n  const [step,setStep]=useState('idle');\n  const [email,setEmail]=useState('');\n  const [demand,setDemand]=useState([\n    {email:'a***@gmail.com',when:'2 ч назад'},{email:'d***@mail.com',when:'вчера'},{email:'r***@outlook.com',when:'2 дня назад'}\n  ]);\n  const alts=EVENTS.filter(x=>x.cat==='concert'&&!x.soldout).slice(0,2);\n  return (\n    <div className=\"mt-4 border border-slate-200 rounded-2xl bg-white p-4\">\n      <div className=\"flex items-center gap-2\">\n        <span className=\"text-[12px] font-bold text-white bg-ink px-2 py-0.5 rounded-full\">SOLD OUT</span>\n        <div className=\"text-[14px] font-bold\">Билетов нет</div>\n        <AIBadge className=\"ml-auto\"/>\n      </div>\n      {step==='idle' && (\n        <div className=\"fade mt-3\">\n          <div className=\"text-[13px] text-slate-600\">Подобрать похожее или сообщить, когда билеты появятся?</div>\n          <div className=\"flex gap-2 mt-3 flex-wrap\">\n            <button onClick={()=>setStep('alt')} className=\"text-[12px] font-bold text-white bg-evb rounded-lg px-3 py-1.5\">Похожие события</button>\n            <button onClick={()=>setStep('form')} className=\"text-[12px] font-bold text-evb border border-evb-100 bg-evb-50 rounded-lg px-3 py-1.5\">Сообщить о билетах</button>\n          </div>\n        </div>\n      )}\n      {step==='alt' && (\n        <div className=\"fade mt-3\">\n          <div className=\"text-[13px] text-slate-600 mb-2\">Ближайшие концерты, на которые есть билеты:</div>\n          <div className=\"grid sm:grid-cols-2 gap-2\">{alts.map(a=><MiniCard key={a.id} e={a} why={`${a.city} · ${dateLabel(a)} — есть места`} onOpen={onOpenEvent}/>)}</div>\n          <button onClick={()=>setStep('form')} className=\"mt-3 text-[12px] text-evb underline\">Не подходит — сообщите про «{e.title}»</button>\n        </div>\n      )}\n      {step==='form' && (\n        <form className=\"fade mt-3\" onSubmit={ev=>{ev.preventDefault();if(email){setDemand(d=>[{email:email.replace(/(.).*(@.*)/,'$1***$2'),when:'только что'},...d]);setStep('done');}}}>\n          <div className=\"text-[13px] text-slate-600 mb-2\">Сообщим первым, как только билеты появятся:</div>\n          <div className=\"flex gap-2\"><input value={email} onChange={ev=>setEmail(ev.target.value)} type=\"email\" required placeholder=\"ваш e-mail\" className=\"flex-1 text-[13px] border border-slate-200 rounded-lg px-3 py-2 outline-none focus:border-evb\"/><button className=\"text-[13px] font-bold text-white bg-evb rounded-lg px-4\">Готово</button></div>\n        </form>\n      )}\n      {step==='done' && <div className=\"fade mt-3 text-[13px] text-emerald-700 bg-emerald-50 rounded-lg px-3 py-2\">Готово — напишем вам первым. Спрос учтён кассой.</div>}\n      <div className=\"mt-4 pt-3 border-t border-slate-100\">\n        <div className=\"text-[12px] text-slate-400 mb-2\">Собранный спрос на это событие ({demand.length}) — видит касса:</div>\n        <div className=\"space-y-1.5\">{demand.map((d,i)=><div key={i} className=\"flex items-center justify-between text-[12px] bg-slate-50 rounded-lg px-3 py-1.5\"><span className=\"font-medium text-slate-600\">{d.email}</span><span className=\"text-slate-400\">{d.when}</span></div>)}</div>\n      </div>\n    </div>\n  );\n}\n\n/* ============================================================\n   СТРАНИЦА СОБЫТИЯ — здесь живут Q&A, Seat Advisor, Demand Catcher\n   ============================================================ */\nfunction EventDetail({e, mobile, onBack, onOpenEvent}){\n  const [seat,setSeat]=useState(false);\n  return (\n    <div className=\"max-w-[1200px] mx-auto px-4 py-6\">\n      <button onClick={onBack} className=\"text-[13px] text-slate-500 hover:text-evb flex items-center gap-1 mb-4\"><svg className=\"w-4 h-4\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" strokeWidth=\"2\"><path d=\"m15 18-6-6 6-6\"/></svg>Все события</button>\n      <div className={mobile?'':'grid grid-cols-2 gap-8'}>\n        <div className={mobile?'mb-5':''}>\n          <Poster e={e} h=\"h-72\" rounded=\"rounded-2xl\"/>\n        </div>\n        <div>\n          {e.tag && <span className=\"inline-block mb-2 text-[11px] font-bold uppercase tracking-wide text-evb bg-evb-50 px-2 py-0.5 rounded\">{e.tag}</span>}\n          <h1 className=\"text-[24px] font-black leading-tight\">{e.title}</h1>\n          <div className=\"mt-2 space-y-1.5 text-[13px] text-slate-600\">\n            <div className=\"flex items-center gap-2\"><CalIcon className=\"w-4 h-4 text-evb\"/> {dateLabel(e)} · {e.time}</div>\n            <div className=\"flex items-center gap-2\"><PinIcon className=\"w-4 h-4 text-evb\"/> {e.city} · {e.venue}</div>\n          </div>\n          <p className=\"mt-3 text-[13px] text-slate-500 leading-relaxed\">{e.desc}</p>\n          <div className=\"mt-4 flex items-center gap-3\">\n            <div><span className=\"text-[12px] text-slate-400\">от </span><span className=\"text-[22px] font-black\">{e.cur}{e.from}</span><span className=\"text-[12px] text-slate-400\"> до {e.cur}{e.to}</span></div>\n          </div>\n\n          {e.soldout\n            ? <DemandCatcher e={e} onOpenEvent={onOpenEvent}/>\n            : <div className=\"mt-4 flex flex-wrap gap-2\">\n                <button className=\"text-[14px] font-bold text-white bg-evb hover:bg-evb-600 rounded-xl px-6 py-3\">Buy ticket</button>\n                {e.seated &&\n                  <button onClick={()=>setSeat(true)} className=\"text-[14px] font-bold text-ink bg-white border-2 border-ink hover:bg-slate-50 rounded-xl px-5 py-3 flex items-center gap-2\">\n                    Подобрать места <AIBadge/>\n                  </button>}\n              </div>}\n\n          {/* Инлайн Q&A — на каждой странице события */}\n          <EventQA e={e}/>\n        </div>\n      </div>\n      {seat && <SeatAdvisorModal e={e} mobile={mobile} onClose={()=>setSeat(false)}/>}\n    </div>\n  );\n}\n\n/* ====== Футер demo.eventobot ====== */\nfunction Footer(){\n  const col=(t,items)=>(<div><div className=\"text-[13px] font-bold mb-2\">{t}</div><div className=\"space-y-1.5 text-[12px] text-slate-400\">{items.map(i=><div key={i} className=\"hover:text-white cursor-pointer\">{i}</div>)}</div></div>);\n  return (\n    <footer className=\"mt-12 bg-ink text-white\">\n      <div className=\"max-w-[1200px] mx-auto px-4 py-9 grid grid-cols-2 md:grid-cols-4 gap-6\">\n        <div>\n          <div className=\"flex items-center gap-2 mb-2\"><span className=\"w-8 h-8 rounded-lg bg-evb grid place-items-center font-black\">e</span><span className=\"font-black\">Demo Eventobot</span></div>\n          <div className=\"text-[12px] text-slate-400\">Билеты на концерты, шоу и спектакли в Европе и Израиле.</div>\n        </div>\n        {col('Info',['FAQ','About','Terms of Use','Services'])}\n        {col('Write us',['+972 50-815-4463','hello@eventobot.net','Подписка на афишу'])}\n        {col('Follow us',['Facebook','Instagram','Telegram','YouTube'])}\n      </div>\n      <div className=\"border-t border-white/10\"><div className=\"max-w-[1200px] mx-auto px-4 py-4 text-[12px] text-slate-400 flex flex-wrap justify-between gap-2\"><span>2026 © Demo Eventobot</span><span>Developed by EventoBot</span></div></div>\n    </footer>\n  );\n}\n\n/* ============================================================\n   ВЕРХНЯЯ ПАНЕЛЬ ПРОТОТИПА (не часть кассы) — навигация по AI\n   ============================================================ */\nconst AI_ITEMS=[\n  {id:'concierge', name:'Concierge', form:'плавающий чат-виджет'},\n  {id:'search',    name:'Smart Search', form:'AI-enriched поиск в шапке'},\n  {id:'qa',        name:'Event Q&A', form:'инлайн-панель на странице'},\n  {id:'seats',     name:'Seat Advisor', form:'ИИ-окно (модалка)'},\n  {id:'demand',    name:'Demand Catcher', form:'блок на sold-out'},\n];\nfunction ProtoRail({active, go, mobile, setMobile}){\n  return (\n    <div className=\"bg-deep text-white\">\n      <div className=\"max-w-[1200px] mx-auto px-4 py-2.5 flex items-center gap-3 flex-wrap\">\n        <span className=\"text-[12px] font-bold flex items-center gap-1.5\"><span className=\"w-2 h-2 rounded-full bg-evb\"></span>AI-прототип поверх demo.eventobot.net</span>\n        <div className=\"flex items-center gap-1.5 flex-wrap\">\n          {AI_ITEMS.map(it=>(\n            <button key={it.id} onClick={()=>go(it.id)} title={it.form}\n              className={`text-[12px] px-2.5 py-1 rounded-md transition ${active===it.id?'bg-evb text-white font-semibold':'bg-white/10 text-slate-200 hover:bg-white/20'}`}>{it.name}</button>\n          ))}\n        </div>\n        <label className=\"ml-auto flex items-center gap-2 text-[12px] text-slate-300\">\n          <span className=\"hidden sm:inline\">Mobile</span>\n          <button onClick={()=>setMobile(m=>!m)} className={`w-9 h-5 rounded-full relative transition ${mobile?'bg-evb':'bg-white/20'}`}><span className={`absolute top-0.5 w-4 h-4 bg-white rounded-full transition-all ${mobile?'left-[18px]':'left-0.5'}`}/></button>\n        </label>\n      </div>\n    </div>\n  );\n}\n\n/* демо-подсказка «что это» для активной фичи */\nfunction FormHint({id}){\n  const it=AI_ITEMS.find(x=>x.id===id); if(!it)return null;\n  return <div className=\"max-w-[1200px] mx-auto px-4\"><div className=\"mt-3 text-[12px] text-slate-500 bg-white border border-slate-200 rounded-lg px-3 py-2 flex items-center gap-2 fade\"><AIBadge/><span className=\"font-semibold text-slate-700\">{it.name}</span> — форма интеграции: {it.form}. Помечено бейджем AI прямо в интерфейсе.</div></div>;\n}\n\n/* ============================================================\n   APP\n   ============================================================ */\nfunction Home({mobile, onOpenEvent, search, setSearch, focusSearch, hint}){\n  const affiche=EVENTS.filter(e=>e.tag).slice(0,4);\n  const list=EVENTS.filter(e=>!e.soldout);\n  const soon=EVENTS.filter(e=>e.dateTo);\n  const res=search?parseQuery(search):null;\n  return (\n    <>\n      <Hero onSearch={setSearch} focus={focusSearch}/>\n      {hint && <FormHint id={hint}/>}\n      {res ? (\n        <Section title=\"Результаты поиска\" sub={`Запрос: «${res.q}»`}>\n          {res.natural && res.f && (\n            <div className=\"mb-4 bg-evb-50 border border-evb-100 rounded-xl px-4 py-3 fade flex flex-wrap items-center gap-2\">\n              <AIBadge/>\n              <span className=\"text-[13px] text-deep\"><b>Ищу:</b> {res.f.kids?'детские/семейные события, ':''}{res.f.city?res.f.city+', ':''}{res.f.weekend?'выходные, ':''}{res.f.max?`до ${EVENTS[0].cur}${res.f.max}`:''}. <span className=\"text-evb\">Верно?</span></span>\n              <div className=\"ml-auto flex gap-2\"><button className=\"text-[12px] font-bold text-white bg-evb rounded-lg px-3 py-1\">Да</button><button onClick={()=>setSearch('')} className=\"text-[12px] text-evb border border-evb-100 rounded-lg px-3 py-1\">Сброс</button></div>\n            </div>\n          )}\n          <div className=\"text-[12px] text-slate-400 mb-3\">{res.list.length} событ{res.list.length===1?'ие':'ий'}{!res.natural&&' · обычный поиск'}</div>\n          <div className={`grid gap-4 ${mobile?'grid-cols-1':'grid-cols-2 md:grid-cols-4'}`}>{res.list.map(e=><EventCard key={e.id} e={e} onOpen={onOpenEvent}/>)}</div>\n          {res.list.length===0 && <div className=\"text-[13px] text-slate-400 py-8 text-center\">Ничего не нашли. Попробуйте другой запрос.</div>}\n        </Section>\n      ) : (\n        <>\n          {/* фильтр городов */}\n          <div className=\"max-w-[1200px] mx-auto px-4 mt-6\">\n            <div className=\"flex gap-2 overflow-x-auto no-sb pb-1\">\n              {CITIES.map((c,i)=><button key={c} className={`text-[12px] whitespace-nowrap px-3 py-1.5 rounded-full border ${i===0?'bg-ink text-white border-ink':'bg-white text-slate-600 border-slate-200 hover:border-evb'}`}>{c}</button>)}\n            </div>\n          </div>\n          <Section title=\"Affiche\" sub=\"Рекомендуемое\">\n            <div className={`grid gap-4 ${mobile?'grid-cols-1':'grid-cols-2 md:grid-cols-4'}`}>{affiche.map(e=><EventCard key={e.id} e={e} onOpen={onOpenEvent}/>)}</div>\n          </Section>\n          <Section title=\"Events list\">\n            <div className={`grid gap-4 ${mobile?'grid-cols-1':'grid-cols-2 md:grid-cols-4'}`}>{list.map(e=><EventCard key={e.id} e={e} onOpen={onOpenEvent}/>)}</div>\n          </Section>\n          <Section title=\"Soon\" sub=\"Скоро в продаже / длительные показы\">\n            <div className={`grid gap-4 ${mobile?'grid-cols-1':'grid-cols-2 md:grid-cols-4'}`}>{soon.map(e=><EventCard key={e.id} e={e} onOpen={onOpenEvent}/>)}</div>\n          </Section>\n        </>\n      )}\n    </>\n  );\n}\n\nfunction App(){\n  const [mobile,setMobile]=useState(false);\n  const [view,setView]=useState({type:'home'});\n  const [search,setSearch]=useState('');\n  const [chat,setChat]=useState(false);\n  const [hint,setHint]=useState(null);\n  const [focusSearch,setFocusSearch]=useState(0);\n  const scroller=useRef();\n\n  const openEvent=e=>{ setView({type:'event',id:e.id}); setHint(null); if(scroller.current)scroller.current.scrollTop=0; };\n  const goHome=()=>{ setView({type:'home'}); setSearch(''); };\n\n  // навигация по AI-продуктам из верхней панели\n  const go=(id)=>{\n    setHint(id);\n    if(id==='concierge'){ setChat(true); }\n    else if(id==='search'){ setView({type:'home'}); setSearch(''); setChat(false); setFocusSearch(x=>x+1); }\n    else if(id==='qa'){ setChat(false); setView({type:'event',id:'fridman'}); }\n    else if(id==='seats'){ setChat(false); setView({type:'event',id:'fridman',openSeat:true}); }\n    else if(id==='demand'){ setChat(false); setView({type:'event',id:'aerosmith'}); }\n    if(scroller.current)scroller.current.scrollTop=0;\n  };\n\n  const ev=view.type==='event'?byId(view.id):null;\n\n  // авто-открытие Seat Advisor при переходе из панели\n  const detailKey = view.type==='event'?view.id+(view.openSeat?'-seat':''):'home';\n\n  const frame=(content)=>(\n    <div className={mobile?'mx-auto':'w-full'} style={mobile?{maxWidth:430}:{}}>{content}</div>\n  );\n\n  return (\n    <div className=\"min-h-screen\">\n      <ProtoRail active={hint} go={go} mobile={mobile} setMobile={setMobile}/>\n      <div ref={scroller} className={`bg-[#f3f4f6] ${mobile?'border-x border-slate-300 max-w-[440px] mx-auto min-h-screen relative overflow-x-hidden':'relative'}`}>\n        <StoreHeader mobile={mobile} onHome={goHome}/>\n        <div key={view.type==='home'?'home'+(search?'-s':''):detailKey} className=\"fade\">\n          {view.type==='home'\n            ? <Home mobile={mobile} onOpenEvent={openEvent} search={search} setSearch={(s)=>{setSearch(s);setView({type:'home'});}} focusSearch={focusSearch} hint={['search','concierge'].includes(hint)?hint:null}/>\n            : <EventWithSeat e={ev} mobile={mobile} onBack={goHome} onOpenEvent={openEvent} openSeat={view.openSeat} hint={hint}/>}\n        </div>\n        <Footer/>\n        <ConciergeWidget mobile={mobile} open={chat} setOpen={setChat} onOpenEvent={openEvent}/>\n      </div>\n    </div>\n  );\n}\n\n// Обёртка, чтобы авто-открыть Seat Advisor по приходу из панели\nfunction EventWithSeat({e, mobile, onBack, onOpenEvent, openSeat, hint}){\n  const [seat,setSeat]=useState(false);\n  useEffect(()=>{ if(openSeat&&e.seated&&!e.soldout)setSeat(true); },[openSeat,e]);\n  return (\n    <>\n      {['qa','seats','demand'].includes(hint) && <FormHint id={hint}/>}\n      <EventDetailInner e={e} mobile={mobile} onBack={onBack} onOpenEvent={onOpenEvent} seat={seat} setSeat={setSeat}/>\n    </>\n  );\n}\nfunction EventDetailInner({e, mobile, onBack, onOpenEvent, seat, setSeat}){\n  return (\n    <div className=\"max-w-[1200px] mx-auto px-4 py-6\">\n      <button onClick={onBack} className=\"text-[13px] text-slate-500 hover:text-evb flex items-center gap-1 mb-4\"><svg className=\"w-4 h-4\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" strokeWidth=\"2\"><path d=\"m15 18-6-6 6-6\"/></svg>Все события</button>\n      <div className={mobile?'':'grid grid-cols-2 gap-8'}>\n        <div className={mobile?'mb-5':''}><Poster e={e} h=\"h-72\" rounded=\"rounded-2xl\"/></div>\n        <div>\n          {e.tag && <span className=\"inline-block mb-2 text-[11px] font-bold uppercase tracking-wide text-evb bg-evb-50 px-2 py-0.5 rounded\">{e.tag}</span>}\n          <h1 className=\"text-[24px] font-black leading-tight\">{e.title}</h1>\n          <div className=\"mt-2 space-y-1.5 text-[13px] text-slate-600\">\n            <div className=\"flex items-center gap-2\"><CalIcon className=\"w-4 h-4 text-evb\"/> {dateLabel(e)} · {e.time}</div>\n            <div className=\"flex items-center gap-2\"><PinIcon className=\"w-4 h-4 text-evb\"/> {e.city} · {e.venue}</div>\n          </div>\n          <p className=\"mt-3 text-[13px] text-slate-500 leading-relaxed\">{e.desc}</p>\n          <div className=\"mt-4\"><span className=\"text-[12px] text-slate-400\">от </span><span className=\"text-[22px] font-black\">{e.cur}{e.from}</span><span className=\"text-[12px] text-slate-400\"> до {e.cur}{e.to}</span></div>\n          {e.soldout\n            ? <DemandCatcher e={e} onOpenEvent={onOpenEvent}/>\n            : <div className=\"mt-4 flex flex-wrap gap-2\">\n                <button className=\"text-[14px] font-bold text-white bg-evb hover:bg-evb-600 rounded-xl px-6 py-3\">Buy ticket</button>\n                {e.seated && <button onClick={()=>setSeat(true)} className=\"text-[14px] font-bold text-ink bg-white border-2 border-ink hover:bg-slate-50 rounded-xl px-5 py-3 flex items-center gap-2\">Подобрать места <AIBadge/></button>}\n              </div>}\n          <EventQA e={e}/>\n        </div>\n      </div>\n      {seat && <SeatAdvisorModal e={e} mobile={mobile} onClose={()=>setSeat(false)}/>}\n    </div>\n  );\n}\n\nReactDOM.createRoot(document.getElementById('root')).render(<App/>);\n</script>\n</body>\n</html>\n";

const REALM = "EventoBot Demo";
// Password is set via environment variable DEMO_PASS (wrangler secret)
function basicAuthResponse() {
  return new Response("Требуется авторизация", {
    status: 401,
    headers: { "WWW-Authenticate": `Basic realm="${REALM}"` },
  });
}

export default {
  async fetch(request, env) {
    const password = env.DEMO_PASS;
    if (!password) return new Response("DEMO_PASS secret not configured", { status: 500 });

    const authHeader = request.headers.get("Authorization") || "";
    if (!authHeader.startsWith("Basic ")) return basicAuthResponse();

    const [user, pass] = atob(authHeader.slice(6)).split(":");
    if (pass !== password) return basicAuthResponse();

    const url = new URL(request.url);
    if (url.pathname === "/" || url.pathname === "/index.html" || url.pathname === "") {
      return new Response(HTML, {
        headers: { "Content-Type": "text/html; charset=utf-8" },
      });
    }
    return new Response("Not found", { status: 404 });
  },
};
